-- news (11)
insert into news (slug, title, description, body, excerpt, category, author, images, status, read_minutes, trending, created_at, updated_at) values
  ('gta-6-release-date-november-19-2026', 'GTA 6 Confirmed for November 19, 2026', 'Rockstar Games confirms Grand Theft Auto VI will launch on November 19, 2026, after moving from its earlier spring target.', 'Rockstar Games has confirmed that Grand Theft Auto VI will release on November 19, 2026 for PlayStation 5 and Xbox Series X|S. The date follows an earlier window of May 26, 2026 that was announced alongside the second trailer.

In its statement, Rockstar thanked players for their patience and said the additional time is needed to finish the game with the level of polish it requires. Parent company Take-Two has repeatedly described GTA VI as the most ambitious project in the studio''s history.

A PC version was not announced for launch — consistent with previous Rockstar releases, where PC has historically followed the console debut.', 'Rockstar pushed the date from May 26 to November 19, 2026, asking fans for extra patience to deliver the level of polish the game demands.', 'Release', 'Editorial Desk', ARRAY['news-release-date', 'news-release-2']::text[], 'confirmed', 4, true, '2025-11-06T00:00:00.000Z', '2025-11-06T00:00:00.000Z'),
  ('trailer-2-everything-revealed', 'Trailer 2 Breakdown: Everything Rockstar Revealed', 'The second official trailer for GTA 6 arrived on May 6, 2025, expanding the cast and showing far more of the state of Leonida.', 'Rockstar released the second official trailer for Grand Theft Auto VI on May 6, 2025, alongside dozens of new screenshots — its deepest look at Leonida yet.

Locations: the trailer toured Vice City''s neon nightlife, the Everglades-style swamps of Grassrivers, the faded coast of Port Gellhorn, the industrial town of Ambrosia, and the island chain of the Leonida Keys.

Story: a bank robbery appears to kick off the plot, Lucia is shown out on parole with an ankle monitor, and corrupt police recur throughout. Rockstar published bios for Cal Hampton, Boobie Ike, Dre''Quan Priest, Real Dimez, Raul Bautista and Brian Heder.

Graphics: the trailer showed a major technical leap — vastly improved hair physics, high-quality water with real-time deformation, enormous draw distances, and detailed lighting and shadows.', 'From Jason and Lucia''s relationship to a sun-soaked tour of Leonida, the second trailer gave the deepest look yet at GTA 6.', 'Trailer', 'Coverage Team', ARRAY['news-trailer2', 'news-trailer2-b', 'news-trailer2-c']::text[], 'confirmed', 7, true, '2025-05-06T00:00:00.000Z', '2025-05-07T00:00:00.000Z'),
  ('jason-and-lucia-dual-protagonists', 'Meet Jason and Lucia: GTA 6''s Dual Protagonists', 'For the first time in the series, Grand Theft Auto VI stars a playable female lead — Lucia — alongside her partner Jason.', 'Grand Theft Auto VI centers on two protagonists: Jason Duval and Lucia Caminos. Lucia is the first female protagonist in the mainline series, introduced in the first trailer inside a Leonida correctional facility.

Rockstar has described the pair as partners bound together by circumstance and loyalty — a relationship the studio has likened to a modern Bonnie and Clyde. The dual-protagonist structure builds on the character-switching foundations of Grand Theft Auto V, though Rockstar has not detailed exactly how switching will work this time.', 'Rockstar frames Jason and Lucia as a modern Bonnie-and-Clyde duo whose partnership anchors the story.', 'Characters', 'Story Desk', ARRAY['news-jason-lucia', 'news-duo-2']::text[], 'confirmed', 5, true, '2023-12-05T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('leonida-state-confirmed-locations', 'The State of Leonida: Every Confirmed Region', 'Vice City is just the start — Rockstar has named several regions across the fictional state of Leonida.', 'Grand Theft Auto VI is set in the fictional U.S. state of Leonida, inspired by Florida. Its centerpiece is a modern Vice City, but Rockstar''s trailers and website point to a far wider map.

Named regions include the island chain of the Leonida Keys, the wetlands of Grassrivers, the faded coastal town of Port Gellhorn, and other areas across the state. Rockstar has called it the largest and most detailed world it has ever created.', 'Vice City, the Leonida Keys, Grassrivers, Port Gellhorn and more make up the largest world Rockstar has built.', 'World', 'Map Team', ARRAY['news-leonida', 'news-leonida-2']::text[], 'trailer_inferred', 6, false, '2025-05-09T00:00:00.000Z', '2025-05-10T00:00:00.000Z'),
  ('gta-6-pc-version-what-we-know', 'GTA 6 on PC: What We Know (and Don''t)', 'A PC version has not been confirmed for launch. Here''s why most expect it to follow — and when.', 'As of now, Grand Theft Auto VI is confirmed only for PlayStation 5 and Xbox Series X|S. Rockstar has not announced a PC version.

That mirrors the studio''s pattern: Grand Theft Auto V launched on consoles in 2013 and only reached PC in 2015. Most observers expect a PC release to follow GTA VI''s console debut, but any timing remains pure speculation until Rockstar says otherwise.', 'History suggests a PC port arrives after the console launch, but Rockstar has made no PC announcement.', 'Platforms', 'Tech Desk', ARRAY['news-pc']::text[], 'speculation', 4, false, '2025-11-08T00:00:00.000Z', '2025-11-08T00:00:00.000Z'),
  ('gta-online-future-after-gta-6', 'What Happens to GTA Online After GTA 6?', 'Rockstar has been quiet on online plans for GTA 6 — but the community has plenty of theories.', 'Grand Theft Auto Online became one of the most successful live-service games of its era, so attention naturally turns to what an online component for GTA VI might look like.

Rockstar has not detailed any online plans for Grand Theft Auto VI. Everything from a fresh online world to continued support for the existing GTA Online remains speculation at this stage.', 'An evolving online mode seems likely given GTA Online''s success, though nothing has been confirmed.', 'Online', 'Community Desk', ARRAY['news-online']::text[], 'speculation', 3, false, '2025-12-01T00:00:00.000Z', '2025-12-01T00:00:00.000Z'),
  ('gta-6-graphics-new-rage-engine', 'GTA 6 Graphics: Inside the New RAGE Engine', 'Trailer 2 revealed a generational leap — ray tracing, lifelike water, hair physics, and procedural detail.', 'Trailer 2 and Rockstar''s screenshots showcased a major technical leap on a new version of the RAGE engine (informally dubbed ''RAGE 9'' by the community).

Water is rendered with high-quality meshes that deform realistically as boats cut through them, with translucency that varies by water type. Shadows are detailed enough to capture individual hair strands and netted windows without shimmering, and large panning shots reveal huge draw distances with smooth world streaming.

Rockstar developers have teased cutting-edge tech including ray tracing, ray-traced global illumination, and procedural generation for objects and environments. Hair physics in particular saw a dramatic improvement over Trailer 1.', 'From ray-traced global illumination to deformable water and improved hair physics, GTA 6 pushes Rockstar''s RAGE engine to a new level.', 'Tech', 'Tech Desk', ARRAY['news-graphics']::text[], 'trailer_inferred', 6, true, '2025-05-15T00:00:00.000Z', '2025-05-15T00:00:00.000Z'),
  ('gta-6-pre-orders-editions-detailed', 'GTA 6 Pre-Orders & Editions Detailed', 'Pre-orders opened June 25, 2026 with two editions and a Vintage Vice City bonus pack.', 'Rockstar opened Grand Theft Auto VI pre-orders on June 25, 2026 across the PlayStation Store, Microsoft Store, Rockstar Games Store, and global retailers.

Two editions are available: the Standard Edition at $79.99 and the Ultimate Edition at $99.99, which adds premium vehicles, weapons, apparel, and story content woven across the game. There is no Special or Collector''s Edition.

Every pre-order includes the Vintage Vice City Pack — a ''55 Vapid Stanier, an Ocean Beach garage, and vintage outfits for Jason and Lucia. The game launches November 19, 2026 on PS5, PS5 Pro, and Xbox Series X|S; physical copies (a code in a box) hit retail from November 12 to support pre-loading.', 'Standard ($79.99) and Ultimate ($99.99) editions, plus a Vintage Vice City Pack for all pre-orders — no Collector''s Edition this time.', 'Release', 'Editorial Desk', ARRAY['news-preorder']::text[], 'confirmed', 4, true, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('gta-6-plays-best-on-ps5-sony', 'Sony Says GTA 6 ''Plays Best on PS5''', 'Sony is touting PS5-specific perks for GTA 6 — DualSense haptics, 3D audio, and ultra-fast load times.', 'Posts circulating from the community point to Sony promoting PlayStation 5 as the best way to play Grand Theft Auto VI, reportedly via a PlayStation Blog post.

The highlighted perks include the DualSense controller''s haptic feedback and integrated speaker, Tempest 3D AudioTech to ''surround yourself in the distinct soundscapes of Leonida,'' and near-instant load times thanks to the PS5''s ultra-high-speed SSD.

It''s worth noting these are platform-marketing points, and it isn''t yet clear how much the experience will actually differ from the Xbox Series X|S version. Rockstar has not detailed platform-specific features itself.', 'DualSense haptic feedback, Tempest 3D AudioTech, and near-instant SSD load times headline Sony''s GTA 6 pitch — though how much differs from Xbox is unclear.', 'Platforms', 'Platforms Desk', ARRAY['news-ps5']::text[], 'speculation', 4, true, '2026-06-28T00:00:00.000Z', '2026-06-28T00:00:00.000Z'),
  ('gta-6-map-size-comparison', 'How Big Is GTA 6''s Map? ~4x Larger Than GTA V', 'Community estimates put Leonida at roughly 125 km²+ — about four times the size of GTA V''s map.', 'Map-size comparisons making the rounds estimate Grand Theft Auto VI''s state of Leonida at roughly 125 km² or more — about four times the size of GTA V''s ~81 km² map, and far larger than San Andreas (~36 km²) or the original Vice City (~16 km²).

These figures are estimates based on in-game data, developer leaks, and community analysis, not official numbers. Rockstar has only said Leonida is the largest and most detailed world it has built. Treat exact sizes as unconfirmed until launch.', 'Based on leaks and community analysis, GTA 6''s Leonida is estimated at ~125 km²+, dwarfing GTA V (~81 km²) and every previous entry.', 'World', 'Map Team', ARRAY['news-mapsize']::text[], 'speculation', 3, true, '2026-06-28T00:00:00.000Z', '2026-06-28T00:00:00.000Z'),
  ('vice-city-stanier-returns', 'Vice City''s Iconic Stanier Returns in GTA 6', 'The classic Vapid Stanier sedan makes its comeback — and you can get a vintage ''55 model free with pre-orders.', 'The Vapid Stanier — a Grand Theft Auto staple since the original Vice City era — is making its return in GTA 6.

A vintage ''55 Vapid Stanier is confirmed as part of the Vintage Vice City Pack included with every pre-order, alongside an Ocean Beach garage. It''s the first GTA 6 vehicle Rockstar has named, and a nod to longtime fans of the series'' Miami-inspired roots.', 'A staple since the original Vice City, the Stanier returns in GTA 6, with a vintage ''55 Vapid Stanier bundled into the pre-order Vintage Vice City Pack.', 'Vehicles', 'Garage', ARRAY['news-stanier']::text[], 'confirmed', 3, false, '2026-06-28T00:00:00.000Z', '2026-06-28T00:00:00.000Z')
