-- guides (6)
insert into guides (slug, title, description, body, category, difficulty, featured, images, status, created_at, updated_at) values
  ('gta-6-release-date-everything-confirmed', 'GTA 6 Release Date: Everything Confirmed', 'The full timeline — from the 2023 reveal to the confirmed November 19, 2026 launch.', 'Grand Theft Auto VI was first revealed on December 4, 2023 with its debut trailer. A second trailer on May 6, 2025 announced a release window of May 26, 2026, which Rockstar later moved to its confirmed date of November 19, 2026.

The game launches on PlayStation 5 and Xbox Series X|S. No PC version has been announced for launch.', 'Release', 'Beginner', true, ARRAY['guide-release', 'guide-release-2']::text[], 'confirmed', '2025-11-07T00:00:00.000Z', '2025-11-07T00:00:00.000Z'),
  ('who-are-jason-and-lucia', 'Who Are Jason and Lucia? Protagonists Explained', 'Everything Rockstar has revealed about GTA 6''s dual leads and their relationship.', 'Jason Duval and Lucia Caminos are the two playable protagonists of Grand Theft Auto VI. Lucia is the series'' first female lead.

Rockstar''s bios describe Jason as someone who grew up around grifters and wants an easy life, and Lucia as someone who has fought for everything she has. Their partnership drives the story.', 'Characters', 'Beginner', true, ARRAY['guide-protagonists']::text[], 'confirmed', '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('leonida-regions-and-real-world-inspirations', 'Leonida Regions & Their Real-World Inspirations', 'A tour of every named region in Leonida and the Florida locations that inspired them.', 'Leonida is modeled on Florida. Vice City draws on Miami; the Leonida Keys mirror the Florida Keys; Grassrivers evokes the Everglades; and Port Gellhorn channels the Florida Panhandle.

This guide breaks down each named area, what we''ve seen of it, and how it maps to the real world.', 'World', 'Intermediate', true, ARRAY['guide-leonida', 'guide-leonida-2']::text[], 'trailer_inferred', '2025-05-12T00:00:00.000Z', '2025-05-12T00:00:00.000Z'),
  ('gta-6-platforms-and-system-requirements', 'GTA 6 Platforms & System Requirements', 'Which consoles run GTA 6 at launch, and what we can guess about an eventual PC release.', 'Grand Theft Auto VI launches on PlayStation 5 and Xbox Series X|S. There is no last-gen (PS4 / Xbox One) version.

A PC release has not been announced. Any PC system requirements are pure speculation until Rockstar confirms a port.', 'Platforms', 'Beginner', false, ARRAY['guide-platforms']::text[], 'confirmed', '2025-11-09T00:00:00.000Z', '2025-11-09T00:00:00.000Z'),
  ('trailer-1-vs-trailer-2-what-changed', 'Trailer 1 vs Trailer 2: What Changed', 'Side-by-side analysis of the two official trailers and the new details the second one revealed.', 'The first trailer (December 2023) introduced Vice City, Lucia, and the tone of the game. The second trailer (May 2025) widened the lens — showing more of Leonida, a larger supporting cast, and a major visual leap.

This guide compares the two shot by shot.', 'Analysis', 'Advanced', false, ARRAY['guide-trailers']::text[], 'trailer_inferred', '2025-05-14T00:00:00.000Z', '2025-05-14T00:00:00.000Z'),
  ('gta-6-pre-order-and-editions', 'GTA 6 Pre-Orders & Editions: What to Expect', 'Pre-orders aren''t live yet — here''s what Rockstar''s past launches suggest may be coming.', 'Rockstar has not opened pre-orders or detailed special editions for Grand Theft Auto VI. Based on prior launches, expect standard and premium editions with in-game bonuses to be announced closer to release.

Treat any edition details circulating now as unconfirmed.', 'Buying', 'Beginner', false, ARRAY['guide-preorder']::text[], 'speculation', '2025-12-02T00:00:00.000Z', '2025-12-02T00:00:00.000Z')
