insert into vehicles (slug, title, description, body, class, manufacturer, images, status, top_speed, created_at, updated_at) values
  ('grotti-cheetah-95', 'Grotti Cheetah ''95', 'A mid-''90s mid-engine exotic — the Cheetah returns, channeling the Ferrari Testarossa and 512 BB.', 'Confirmed in the Ultimate Edition lineup, the Grotti Cheetah ''95 is a classic mid-engine supercar inspired by the Ferrari Testarossa and 512 BB. Performance figures are estimates pending official stats.', 'Sports Classics', 'Grotti', ARRAY['/images/vehicles/grotti-cheetah-95.jpg']::text[], 'confirmed', 195, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('schyster-deviant', 'Schyster Deviant', 'Early-''70s American muscle inspired by the 1972 AMC Javelin.', 'An Ultimate Edition muscle car drawing on the 1972 AMC Javelin — long hood, aggressive stance, classic V8 energy.', 'Muscle', 'Schyster', ARRAY['/images/vehicles/schyster-deviant.jpg']::text[], 'confirmed', 130, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('vapid-dominator-buggy-67', 'Vapid Dominator Buggy ''67', 'An off-road build of a first-generation Ford Mustang — rugged and trail-ready.', 'Part of the Ultimate Edition pack, the Dominator Buggy ''67 reimagines a first-generation Ford Mustang as a raw off-road machine.', 'Off-Road', 'Vapid', ARRAY['/images/vehicles/vapid-dominator-buggy-67.jpg']::text[], 'confirmed', 120, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('dinka-enduro', 'Dinka Enduro', 'A dual-sport motorcycle inspired by classic Honda XL350, XR500 and CB models.', 'An Ultimate Edition dual-sport bike channeling vintage Honda XL350, XR500 and CB motorcycles — equally at home on road and trail.', 'Motorcycle', 'Dinka', ARRAY['/images/vehicles/dinka-enduro.jpg']::text[], 'confirmed', 95, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('crest-kayak', 'Crest Kayak', 'A paddle kayak for exploring Leonida''s waterways — based on the Crescent Kayak.', 'An Ultimate Edition watercraft based on the Crescent Kayak, ideal for quietly navigating the wetlands and coast of Leonida.', 'Boat', 'Crest', ARRAY['/images/vehicles/crest-kayak.jpg']::text[], 'confirmed', 8, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('declasse-mamba-gt', 'Declasse Mamba GT', 'A ''60s racing coupe inspired by the Shelby Daytona Coupe.', 'An Ultimate Edition sports classic modeled on the Shelby Daytona Coupe — a sleek, race-bred grand tourer.', 'Sports Classics', 'Declasse', ARRAY['/images/vehicles/declasse-mamba-gt.jpg']::text[], 'confirmed', 160, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('vapid-riata-classic', 'Vapid Riata Classic', 'A classic off-road SUV channeling the first-generation Ford Bronco.', 'An Ultimate Edition SUV inspired by the first-generation Ford Bronco — boxy, capable, and built for the backcountry.', 'SUV', 'Vapid', ARRAY['/images/vehicles/vapid-riata-classic.jpg']::text[], 'confirmed', 105, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('sirius', 'Sirius', 'A 1970s muscle car inspired by the 1970 Mercury Cougar.', 'An Ultimate Edition muscle car drawing on the 1970 Mercury Cougar — long, low, and unmistakably American.', 'Muscle', 'Unconfirmed', ARRAY['/images/vehicles/sirius.jpg']::text[], 'confirmed', 135, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('shitzu-squalo', 'Shitzu Squalo', 'A sleek speedboat for tearing across the Leonida coast.', 'An Ultimate Edition speedboat built for the open water around Vice City and the Leonida Keys.', 'Boat', 'Shitzu', ARRAY['/images/vehicles/shitzu-squalo.jpg']::text[], 'confirmed', 90, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z'),
  ('vapid-stanier-55', 'Vapid Stanier ''55', 'A vintage 1955 sedan — free with every pre-order via the Vintage Vice City Pack.', 'The ''55 Vapid Stanier is a classic 1950s sedan included with every pre-order as part of the Vintage Vice City Pack, alongside an Ocean Beach garage. It''s the first GTA 6 vehicle Rockstar named.', 'Sedan', 'Vapid', ARRAY['/images/vehicles/vapid-stanier-55.jpg']::text[], 'confirmed', 90, '2026-06-25T00:00:00.000Z', '2026-06-25T00:00:00.000Z')
