-- characters (8)
insert into characters (slug, title, description, body, role, affiliation, images, status, voice_actor, created_at, updated_at) values
  ('lucia-caminos', 'Lucia Caminos', 'The series'' first female protagonist — out on parole with everything to prove.', 'Lucia Caminos is one of two playable protagonists in Grand Theft Auto VI and the first female lead in the mainline series. Introduced in the first trailer leaving a Leonida correctional facility, she''s out on parole — an ankle monitor appears in several Trailer 2 scenes, a reminder she''s still being watched. Her relationship with Jason is the emotional core of the story, a partnership Rockstar frames as a modern Bonnie and Clyde.', 'Protagonist', 'Jason & Lucia', ARRAY['/images/characters/lucia-caminos.jpg']::text[], 'confirmed', NULL, '2023-12-04T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('jason-duval', 'Jason Duval', 'Lucia''s partner — ex-Army, now running jobs for a Keys drug smuggler and wanting out.', 'Jason Duval is the second playable protagonist. He grew up around criminals, joined the US Army to try to straighten his life out, and ended up in the Leonida Keys doing jobs for drug smuggler Brian Heder — living rent-free in exchange for dirty work. He wants an easy life, but trouble keeps finding him and Lucia.', 'Protagonist', 'Jason & Lucia', ARRAY['/images/characters/jason-duval.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('cal-hampton', 'Cal Hampton', 'Jason''s loyal buddy — happiest at home with a beer and the Coast Guard radio.', 'Cal Hampton is Jason''s friend who feels safest at home, drinking beers and listening to Coast Guard comms. Loyal but not the ambitious type, he''s Jason''s connection to chatter and information from the fringes.', 'Associate', 'Jason''s circle', ARRAY['/images/characters/cal-hampton.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('boobie-ike', 'Boobie Ike', 'A Vice City legend who turned street life into real estate, a strip club, and a record label.', 'Boobie Ike is a Vice City legend who turned the street life into real business — real estate, a strip club called the Jack of Hearts, and a recording studio. He''s partnered with music hustler Dre''Quan Priest.', 'Businessman', 'Vice City', ARRAY['/images/characters/boobie-ike.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('drequan-priest', 'Dre''Quan Priest', 'A music hustler running Only Raw Records, betting on the rap duo Real Dimez.', 'Dre''Quan Priest is a music hustler who runs Only Raw Records and signed the viral rap duo Real Dimez. Partnered with Boobie Ike, he''s chasing a breakout out of Leonida''s music scene.', 'Music Mogul', 'Only Raw Records', ARRAY['/images/characters/drequan-priest.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('real-dimez', 'Real Dimez', 'The viral rap duo signed to Only Raw Records.', 'Real Dimez is a rap duo signed to Dre''Quan Priest''s Only Raw Records — internet-famous performers riding their viral moment in Leonida''s music scene.', 'Rap Duo', 'Only Raw Records', ARRAY['/images/characters/real-dimez.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('raul-bautista', 'Raul Bautista', 'A bank robber assembling the crew for the score that kicks off the story.', 'Raul Bautista is an experienced robber putting together a crew for ambitious jobs. The bank robbery he sets up looks to be the heist that kicks off the whole story — pulling Jason and Lucia toward serious risk.', 'Robber', 'Bautista crew', ARRAY['/images/characters/raul-bautista.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('brian-heder', 'Brian Heder', 'The older drug smuggler Jason works for in the Keys.', 'Brian Heder is an older drug smuggler operating out of the Leonida Keys. He lets Jason live rent-free in exchange for doing his dirty work — one of the figures whose business pulls Jason deeper in.', 'Smuggler', 'Leonida Keys', ARRAY['/images/characters/brian-heder.jpg']::text[], 'confirmed', NULL, '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z')
