-- locations (6)
insert into locations (slug, title, description, body, region, type, coordinates, images, status, created_at, updated_at) values
  ('vice-city', 'Vice City', 'Rockstar''s modern reimagining of Miami — the neon-soaked heart of Leonida.', 'Vice City returns as the centerpiece of Grand Theft Auto VI — a modern reimagining of Miami and the primary urban center of Leonida. Beaches, Art Deco facades, nightlife, and a dense, vertical skyline define the city at the heart of the map.', 'Vice City', 'City', '{"x":64,"y":68}'::jsonb, ARRAY['loc-vicecity', 'loc-vicecity-2']::text[], 'confirmed', '2023-12-04T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('leonida-keys', 'Leonida Keys', 'An island chain based on the Florida Keys — Jason''s home turf.', 'The Leonida Keys are an island chain based on the real Florida Keys, with scenic coastal highways linking sun-bleached islands. It''s where Jason lives at the start of the game, running jobs for smuggler Brian Heder.', 'Leonida Keys', 'Islands', '{"x":58,"y":90}'::jsonb, ARRAY['loc-keys']::text[], 'confirmed', '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('grassrivers', 'Grassrivers', 'Rockstar''s take on the Everglades — swamps, marshland, and isolated rural communities.', 'Grassrivers is Leonida''s wetlands region, inspired by the Florida Everglades: swamps, marshland, slow-moving rivers, cypress forests, and isolated rural communities. Trailer footage shows airboats skimming across the water.', 'Grassrivers', 'Wetlands', '{"x":46,"y":76}'::jsonb, ARRAY['loc-grassrivers']::text[], 'confirmed', '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('port-gellhorn', 'Port Gellhorn', 'Leonida''s ''forgotten coast'' — cheap motels, shut-down attractions, and empty strip malls.', 'Port Gellhorn is Leonida''s forgotten coast — a grittier counterpoint to Vice City''s glamour, with cheap motels, shuttered roadside attractions, and empty strip malls along a faded panhandle shoreline.', 'Port Gellhorn', 'Town', '{"x":22,"y":26}'::jsonb, ARRAY['loc-portgellhorn']::text[], 'confirmed', '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('ambrosia', 'Ambrosia', 'Old-school industrial heartland — home to the Allied Crystal sugar refinery.', 'Ambrosia is where American industry and old-school values reign — inland country anchored by the Allied Crystal sugar refinery. It''s described as ''what''s keeping Leonida sweet,'' a working-town contrast to the glitz of the coast.', 'Ambrosia', 'Town', '{"x":40,"y":48}'::jsonb, ARRAY['loc-ambrosia']::text[], 'confirmed', '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z'),
  ('mount-kalliga', 'Mount Kalaga', 'Leonida''s elevated highlands — forests, lakes, and dangerous wildlife.', 'Mount Kalaga is Leonida''s highland region — forested terrain with lakes, rivers, and mountains, often compared to Red Dead Redemption 2''s Ambarino. Expect dangerous wildlife including bears and panthers far from the city lights.', 'Mount Kalaga', 'Wilderness', '{"x":52,"y":30}'::jsonb, ARRAY['loc-kalliga']::text[], 'confirmed', '2025-05-06T00:00:00.000Z', '2025-05-06T00:00:00.000Z')
